@Test(timeout=1000)
    public void sortArrayTest() {
        for (int i = 0; i < 50; i++) {
            int[] random = getSortArray(new Random().nextInt(200)+1);
            assertArrayEquals(random, new Sort().sort(random));
        }
    }

